package com.hiliving.content.news;import com.hiliving.admin.audit.AuditService;import com.hiliving.api.error.ApiRequestException;import org.springframework.data.domain.Sort;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;
@Service public class NewsService{private final NewsRepository news;private final AuditService audit;private final Clock clock=Clock.systemUTC();public NewsService(NewsRepository news,AuditService audit){this.news=news;this.audit=audit;}@Transactional(readOnly=true)public List<NewsResponse> publicList(){return news.findPublic(clock.instant()).stream().map(NewsResponse::from).toList();}@Transactional(readOnly=true)public NewsResponse publicFind(String slug){return NewsResponse.from(news.findPublicBySlug(slug,clock.instant()).orElseThrow(()->new ApiRequestException(HttpStatus.NOT_FOUND,"NEWS_NOT_FOUND","News article was not found")));}@Transactional(readOnly=true)public List<NewsResponse> adminList(String search){String q=search==null?"":search.trim().toLowerCase(Locale.ROOT);return news.findAll(Sort.by("displayOrder").and(Sort.by(Sort.Direction.DESC,"createdAt"))).stream().filter(n->q.isEmpty()||n.getTitle().toLowerCase(Locale.ROOT).contains(q)||n.getSlug().contains(q)).map(NewsResponse::from).toList();}@Transactional(readOnly=true)public NewsResponse find(Long id){return NewsResponse.from(require(id));}@Transactional public NewsResponse create(NewsRequest r){slug(r.slug(),null);NewsEntity n=news.saveAndFlush(NewsEntity.create(r));audit.record(r.published()?"NEWS_PUBLISHED":"NEWS_CREATED","NEWS",n.getId(),n.getSlug());return NewsResponse.from(n);}@Transactional public NewsResponse update(Long id,NewsRequest r){NewsEntity n=require(id);slug(r.slug(),id);boolean was=n.isPublished();boolean thumbnailChanged=!Objects.equals(n.getThumbnailUrl(),clean(r.thumbnailUrl()));n.update(r);news.flush();String action=!was&&r.published()?"NEWS_PUBLISHED":was&&!r.published()?"NEWS_UNPUBLISHED":"NEWS_UPDATED";audit.record(action,"NEWS",id,n.getSlug());if(thumbnailChanged)audit.record("NEWS_THUMBNAIL_CHANGED","NEWS",id,null);return NewsResponse.from(n);}@Transactional public void delete(Long id){NewsEntity n=require(id);news.delete(n);audit.record("NEWS_DELETED","NEWS",id,n.getSlug());}private void slug(String slug,Long id){if(news.existsBySlugAndIdNot(slug,id==null?-1L:id))throw new ApiRequestException(HttpStatus.CONFLICT,"NEWS_SLUG_CONFLICT","News slug is already in use");}private NewsEntity require(Long id){return news.findById(id).orElseThrow(()->new ApiRequestException(HttpStatus.NOT_FOUND,"NEWS_NOT_FOUND","News article was not found"));}private static String clean(String value){return value==null||value.isBlank()?null:value.trim();}}
